// Fetch all data sources needed for the Action Recommender
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base   = 'YOUR_SUPABASE_REST_URL';
const hdr    = { apikey, Authorization: `Bearer ${apikey}` };

const now = new Date();
const centralStr = now.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const centralHour = Number(now.toLocaleString('en-US', { timeZone: 'America/Chicago', hour: 'numeric', hour12: false }));

// Compute Monday of current week (CST)
const centralNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' }));
const dayOfWeek = centralNow.getDay(); // 0=Sun, 1=Mon, ...
const mondayOffset = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const monday = new Date(centralNow);
monday.setDate(monday.getDate() - mondayOffset);
const mondayStr = monday.toISOString().slice(0, 10);

const [roster, weeklyData, intradayData, pipelineData, poolData] = await Promise.all([
  // Active agents across all tiers
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/agents?select=name,site,tier,manager&is_active=eq.true`,
    headers: hdr, json: true,
  }),
  // Weekly daily_scrape_data (Mon through today)
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/daily_scrape_data?select=agent_name,scrape_date,ib_leads_delivered,ob_leads_delivered,ib_sales,ob_sales,custom_sales&scrape_date=gte.${mondayStr}&scrape_date=lte.${centralStr}&order=scrape_date.asc`,
    headers: hdr, json: true,
  }),
  // Latest intraday snapshot per agent today
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/intraday_snapshots?select=agent_name,total_dials,talk_time_minutes,ib_leads_delivered,ib_sales,ob_leads_delivered,ob_sales,ib_premium,ob_premium,custom_premium,pool_dials,pool_talk_minutes,pool_self_assigned,pool_answered,pool_long_calls&scrape_date=eq.${centralStr}&order=scrape_hour.desc`,
    headers: hdr, json: true,
  }),
  // Latest pipeline compliance for today
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/pipeline_compliance_daily?select=agent_name,past_due_follow_ups,new_leads,call_queue_count,todays_follow_ups&scrape_date=eq.${centralStr}`,
    headers: hdr, json: true,
  }),
  // Latest leads pool data for today
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/leads_pool_daily_data?select=agent_name,calls_made,talk_time_minutes,self_assigned_leads,answered_calls,long_calls,sales_made&scrape_date=eq.${centralStr}`,
    headers: hdr, json: true,
  }),
]);

if (!roster || roster.length === 0) {
  throw new Error('No active agents found');
}

// Build roster lookup
const rosterMap = {};
for (const a of roster) rosterMap[a.name] = a;

// Build weekly stats per agent
const weeklyByAgent = {};
for (const r of (weeklyData || [])) {
  if (!rosterMap[r.agent_name]) continue;
  if (!weeklyByAgent[r.agent_name]) weeklyByAgent[r.agent_name] = [];
  weeklyByAgent[r.agent_name].push({
    date: r.scrape_date,
    ibLeads: r.ib_leads_delivered || 0,
    obLeads: r.ob_leads_delivered || 0,
    ibSales: r.ib_sales || 0,
    obSales: r.ob_sales || 0,
    customSales: r.custom_sales || 0,
  });
}

// Build intraday map (latest per agent)
const intradayMap = {};
for (const r of (intradayData || [])) {
  if (!intradayMap[r.agent_name] && rosterMap[r.agent_name]) {
    intradayMap[r.agent_name] = r;
  }
}

// Build pipeline map
const pipeMap = {};
for (const r of (pipelineData || [])) {
  if (rosterMap[r.agent_name]) pipeMap[r.agent_name] = r;
}

// Build pool map
const poolMapData = {};
for (const r of (poolData || [])) {
  if (rosterMap[r.agent_name]) poolMapData[r.agent_name] = r;
}

return [{
  json: {
    scrapeDate: centralStr,
    centralHour,
    mondayStr,
    rosterMap,
    weeklyByAgent,
    intradayMap,
    pipeMap,
    poolMapData,
    agentCount: roster.length,
  }
}];

const { scrapeDate, centralHour, rosterMap, weeklyByAgent, intradayMap, pipeMap, poolMapData, agentCount } = $input.first().json;

// ── Tier configs (mirroring client/src/lib/tierTargets.ts) ──
const TIER_CONFIGS = {
  T1: { CR_TARGET: 25, CR_FLOOR: 20, CR_CRISIS: 15, CR_CRISIS_DAYS: 3, MAX_PIPELINE: 25, LEAD_COST: 83, hasPool: false },
  T2: { CR_TARGET: 20, CR_FLOOR: 15, CR_CRISIS: 10, CR_CRISIS_DAYS: 3, MAX_PIPELINE: 40, LEAD_COST: 73, hasPool: true },
  T3: { CR_TARGET: 5,  CR_FLOOR: 4,  CR_CRISIS: 3,  CR_CRISIS_DAYS: 3, MAX_PIPELINE: 120, LEAD_COST: 15, hasPool: true },
};

function computeWeeklyCR(rows, tier) {
  if (!rows || rows.length === 0) return { weeklyCR: null, dailyCRs: [] };
  const isIB = tier === 'T1' || tier === 'T2';
  const dailyCRs = rows.map(r => {
    const leads = isIB ? r.ibLeads : (r.obLeads || r.ibLeads);
    const sales = isIB ? r.ibSales : (r.obSales || r.ibSales + r.obSales + r.customSales);
    return leads > 0 ? (sales / leads) * 100 : 0;
  });
  const totalL = rows.reduce((s, r) => s + (isIB ? r.ibLeads : (r.obLeads || r.ibLeads)), 0);
  const totalS = rows.reduce((s, r) => s + (isIB ? r.ibSales : (r.obSales || r.ibSales + r.obSales + r.customSales)), 0);
  return { weeklyCR: totalL > 0 ? (totalS / totalL) * 100 : null, dailyCRs };
}

function consLow(dailyCRs, threshold) {
  let c = 0;
  for (let i = dailyCRs.length - 1; i >= 0; i--) { if (dailyCRs[i] < threshold) c++; else break; }
  return c;
}

function recommend(tier, cfg, weeklyCR, dailyCRs, pipe, pool) {
  const pastDue = pipe?.past_due_follow_ups ?? 0;
  const callQueue = pipe?.call_queue_count ?? 0;
  const pipeSize = (pipe?.new_leads ?? 0) + (pipe?.todays_follow_ups ?? 0) + pastDue;
  const poolDials = pool?.calls_made ?? 0;
  const consLowDays = consLow(dailyCRs, cfg.CR_CRISIS);

  // T1 / T2 shared critical checks
  if (tier !== 'T3') {
    if (pastDue > 3) return { action: 'WORK_FOLLOWUPS', severity: 'critical', reason: `${pastDue} past due follow-ups — $${pastDue * cfg.LEAD_COST} in lead spend rotting. Work these before taking any new calls.` };
    if (pipeSize > cfg.MAX_PIPELINE) return { action: 'CLEAR_PIPELINE', severity: 'critical', reason: `Pipeline at ${pipeSize} leads (max ${cfg.MAX_PIPELINE}). Close out stale leads.` };
    if (consLowDays >= cfg.CR_CRISIS_DAYS && weeklyCR !== null) return { action: 'REVIEW_QUALITY', severity: 'critical', reason: `CR below ${cfg.CR_CRISIS}% for ${consLowDays} consecutive days (weekly: ${weeklyCR.toFixed(0)}%).` };
    if (pastDue > 0) return { action: 'WORK_FOLLOWUPS', severity: 'warning', reason: `${pastDue} past due follow-up${pastDue > 1 ? 's' : ''} — work these first.` };
    if (weeklyCR !== null && weeklyCR < cfg.CR_FLOOR) return { action: 'WORK_FOLLOWUPS', severity: 'warning', reason: `Weekly CR at ${weeklyCR.toFixed(0)}% (target: ${cfg.CR_TARGET}%+). Focus on converting existing pipeline.` };
  }

  // T1 specific
  if (tier === 'T1') {
    if (weeklyCR !== null && weeklyCR >= cfg.CR_TARGET && pipeSize < 15 && pastDue === 0)
      return { action: 'TAKE_MORE_LEADS', severity: 'info', reason: `CR at ${weeklyCR.toFixed(0)}% with clean pipeline (${pipeSize} leads). Capacity available.` };
    return { action: 'ON_TRACK', severity: 'info', reason: `${weeklyCR !== null ? 'CR ' + weeklyCR.toFixed(0) + '%' : ''} · Pipeline ${pipeSize} · Past due ${pastDue} — on track.` };
  }

  // T2 specific
  if (tier === 'T2') {
    if (pipeSize < 10 && poolDials === 0) return { action: 'GET_IN_POOL', severity: 'warning', reason: `Light pipeline at ${pipeSize} leads with zero pool dials. Pool session needed.` };
    if (weeklyCR !== null && weeklyCR >= cfg.CR_TARGET + 5 && pipeSize < 25 && pastDue === 0)
      return { action: 'TAKE_MORE_LEADS', severity: 'info', reason: `IB CR at ${weeklyCR.toFixed(0)}% — closing strong. Eligible for bonus leads.` };
    if (pipeSize < 10) return { action: 'GET_IN_POOL', severity: 'info', reason: `Pipeline at ${pipeSize} leads — pool sessions will build tomorrow's follow-ups.` };
    return { action: 'ON_TRACK', severity: 'info', reason: `${weeklyCR !== null ? 'IB CR ' + weeklyCR.toFixed(0) + '%' : ''} · Pipeline ${pipeSize} · Pool ${poolDials} — on track.` };
  }

  // T3
  if (pastDue > 0) return { action: 'WORK_FOLLOWUPS', severity: 'critical', reason: `${pastDue} past due — work appointments before any pool/queue activity.` };
  if (callQueue > 200) return { action: 'CLEAR_PIPELINE', severity: 'critical', reason: `Queue bloated at ${callQueue}. Stop pool. Withdraw leads past 6 attempts.` };
  if (consLowDays >= cfg.CR_CRISIS_DAYS && weeklyCR !== null) return { action: 'REVIEW_QUALITY', severity: 'critical', reason: `CR below ${cfg.CR_CRISIS}% for ${consLowDays} days (weekly: ${weeklyCR.toFixed(0)}%).` };
  if (callQueue > cfg.MAX_PIPELINE) return { action: 'CLEAR_PIPELINE', severity: 'warning', reason: `Queue at ${callQueue} (max ${cfg.MAX_PIPELINE}). Reduce pool, enforce withdrawals.` };
  if (callQueue < 50) return { action: 'GET_IN_POOL', severity: 'warning', reason: `Queue light at ${callQueue}. Increase pool time and self-assigns.` };
  return { action: 'ON_TRACK', severity: 'info', reason: `${weeklyCR !== null ? 'CR ' + weeklyCR.toFixed(0) + '%' : ''} · Queue ${callQueue} · Past due ${pastDue} — on track.` };
}

// ── Run recommender for all agents ──
const results = [];
for (const [name, agent] of Object.entries(rosterMap)) {
  const tier = agent.tier;
  const cfg = TIER_CONFIGS[tier];
  if (!cfg) continue;
  const weekRows = weeklyByAgent[name] || [];
  const { weeklyCR, dailyCRs } = computeWeeklyCR(weekRows, tier);
  const pipe = pipeMap[name];
  const pool = poolMapData[name];
  const intra = intradayMap[name];

  const rec = recommend(tier, cfg, weeklyCR, dailyCRs, pipe, pool);
  results.push({
    name, tier, site: agent.site, manager: agent.manager || null,
    ...rec,
    weeklyCR: weeklyCR !== null ? Math.round(weeklyCR) : null,
    pastDue: pipe?.past_due_follow_ups ?? null,
    callQueue: pipe?.call_queue_count ?? null,
    pipelineSize: pipe ? (pipe.new_leads ?? 0) + (pipe.todays_follow_ups ?? 0) + (pipe.past_due_follow_ups ?? 0) : null,
    poolDials: pool?.calls_made ?? 0,
    todaysDials: intra?.total_dials ?? 0,
    todaysTalkMin: intra?.talk_time_minutes ?? 0,
  });
}

// Sort: critical first, then warning, then info
const sev = { critical: 0, warning: 1, info: 2 };
results.sort((a, b) => sev[a.severity] - sev[b.severity]);

const critical = results.filter(r => r.severity === 'critical');
const warning  = results.filter(r => r.severity === 'warning');
const onTrack  = results.filter(r => r.severity === 'info');

return [{ json: { scrapeDate, centralHour, agentCount, critical, warning, onTrack, results } }];

const { scrapeDate, centralHour, critical, warning, onTrack, agentCount } = $input.first().json;

// Format date for display
const [y, mo, d] = scrapeDate.split('-');
const dt = new Date(+y, +mo - 1, +d);
const dn = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][dt.getDay()];
const mn = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][dt.getMonth()];
const dd = `${dn} ${mn} ${+d}, ${y}`;
const ampm = centralHour > 12 ? `${centralHour - 12}:05 PM` : `${centralHour}:05 AM`;

const ACTION_LABELS = {
  TAKE_MORE_LEADS: 'TAKE MORE LEADS',
  WORK_FOLLOWUPS: 'WORK FOLLOW-UPS',
  GET_IN_POOL: 'GET IN POOL',
  CLEAR_PIPELINE: 'CLEAR PIPELINE',
  REVIEW_QUALITY: 'REVIEW QUALITY',
  ON_TRACK: 'ON TRACK',
};

const blocks = [];

blocks.push({ type: 'header', text: { type: 'plain_text', text: `Hourly Action Check — ${dd}` } });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text:
  `*${ampm} CT*  ·  ${agentCount} agents tracked\n\n` +
  `*${critical.length}* need attention  ·  *${warning.length}* warnings  ·  *${onTrack.length}* on track`
}});

blocks.push({ type: 'divider' });

// Critical agents
if (critical.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*:rotating_light: CRITICAL (${critical.length})*` } });
  for (const a of critical.slice(0, 10)) {
    const crStr = a.weeklyCR !== null ? `Weekly CR: ${a.weeklyCR}%` : '';
    const pdStr = a.pastDue !== null ? `Past Due: ${a.pastDue}` : '';
    const qStr  = a.tier === 'T3' && a.callQueue !== null ? `Queue: ${a.callQueue}` : '';
    const pStr  = a.pipelineSize !== null ? `Pipeline: ${a.pipelineSize}` : '';
    const stats = [crStr, pdStr, a.tier === 'T3' ? qStr : pStr].filter(Boolean).join(' | ');
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text:
      `*${ACTION_LABELS[a.action] || a.action}* — *${a.name}*  _(${a.tier}, ${a.site})_\n` +
      `${stats}\n` +
      `_↳ ${a.reason}_`
    }});
  }
  if (critical.length > 10) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_…and ${critical.length - 10} more critical._` }] });
  }
  blocks.push({ type: 'divider' });
}

// Warning agents
if (warning.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*:warning: WARNING (${warning.length})*` } });
  for (const a of warning.slice(0, 10)) {
    const crStr = a.weeklyCR !== null ? `Weekly CR: ${a.weeklyCR}%` : '';
    const pdStr = a.pastDue !== null ? `Past Due: ${a.pastDue}` : '';
    const qStr  = a.tier === 'T3' && a.callQueue !== null ? `Queue: ${a.callQueue}` : '';
    const pStr  = a.pipelineSize !== null ? `Pipeline: ${a.pipelineSize}` : '';
    const poolStr = a.poolDials > 0 ? `Pool: ${a.poolDials}` : '';
    const stats = [crStr, pdStr, a.tier === 'T3' ? qStr : pStr, poolStr].filter(Boolean).join(' | ');
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text:
      `*${ACTION_LABELS[a.action] || a.action}* — *${a.name}*  _(${a.tier}, ${a.site})_\n` +
      `${stats}\n` +
      `_↳ ${a.reason}_`
    }});
  }
  if (warning.length > 10) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_…and ${warning.length - 10} more warnings._` }] });
  }
  blocks.push({ type: 'divider' });
}

// On Track summary
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text:
  `*On Track:* ${onTrack.length} agents  |  Targets: T1 CR 25-30% · T2 IB CR 20-25% · T3 CR 4%+  |  Pipeline: T1 ≤25 · T2 ≤40 · T3 Queue ≤120`
}]});

const fallback = `Hourly Action Check — ${dd} ${ampm}: ${critical.length} critical, ${warning.length} warning, ${onTrack.length} on track`;

return [{ json: { text: fallback, blocks } }];

return [{ json: {
  text: ':x: *Hourly Action Alert failed*\n' + ($input.first().json.error || $input.first().json.message || 'Unknown error — check n8n execution log.')
} }];
